// On prend tous les items du node précédent
const items = $input.all();

return items.map((item, index) => {
  const pdfText = item.json.text || "";
  const api = $('Scrape BOAMP').all()[index]?.json.results?.[0] || {};

  // Parse le champ donnees pour extraire les infos détaillées
  let donnees = {};
  try {
    donnees = typeof api.donnees === "string" ? JSON.parse(api.donnees) : api.donnees;
  } catch(e) {}

  // Extrait les organisations
  const notice = donnees?.EFORMS?.ContractNotice || {};
  const efext = notice?.['ext:UBLExtensions']?.['ext:UBLExtension']?.['ext:ExtensionContent']?.['efext:EformsExtension'] || {};
  const orgsRaw = efext?.['efac:Organizations']?.['efac:Organization'];
  const orgs = Array.isArray(orgsRaw) ? orgsRaw : [orgsRaw];

  // Prend le premier organisme (acheteur principal)
  const org = orgs?.[0]?.['efac:Company'] || {};
  const contact = org?.['cac:Contact'] || {};
  const address = org?.['cac:PostalAddress'] || {};

  // Projet principal
  const project = notice?.['cac:ProcurementProject'] || {};
  const lotProject = notice?.['cac:ProcurementProjectLot']?.['cac:ProcurementProject'] || {};

  // Montant estimé
  const montant = project?.['cac:RequestedTenderTotal']?.['cbc:EstimatedOverallContractAmount']?.['#text'] || "";

  // Lots
  const lotDesc = lotProject?.['cbc:Description']?.['#text'] || lotProject?.['cbc:Name']?.['#text'] || "";

  // Construction du texte fusionné pour le LLM
  const apiText = `=== DONNÉES BOAMP API ===
Objet : ${api.objet || ""}
Acheteur : ${api.nomacheteur || ""}
Nom complet organisme : ${org?.['cac:PartyName']?.['cbc:Name']?.['#text'] || ""}
Date parution : ${api.dateparution || ""}
Date limite réponse : ${api.datelimitereponse || ""}
Titulaire : ${api.titulaire || ""}
Type procédure : ${api.procedure_libelle || ""}
Nature avis : ${api.nature_libelle || ""}
URL avis : ${api.url_avis || ""}

=== ACHETEUR ===
Téléphone : ${contact?.['cbc:Telephone'] || ""}
Email : ${contact?.['cbc:ElectronicMail'] || ""}
Rue : ${address?.['cbc:StreetName'] || ""}
Ville : ${address?.['cbc:CityName'] || ""}
Code postal : ${address?.['cbc:PostalZone'] || ""}
Pays : ${address?.['cac:Country']?.['cbc:IdentificationCode']?.['#text'] || ""}
Site web acheteur : ${org?.['cbc:WebsiteURI'] || ""}
Profil acheteur : ${org?.['cbc:EndpointID'] || notice?.['cac:ContractingParty']?.['cbc:BuyerProfileURI'] || ""}

=== MARCHÉ ===
Titre : ${project?.['cbc:Name']?.['#text'] || ""}
Description : ${project?.['cbc:Description']?.['#text'] || ""}
Montant estimé : ${montant}
Description lot : ${lotDesc}

=== TEXTE PDF ===
${pdfText}`;

  return { json: { text: apiText } };
});

const scheduleData = $('Schedule Trigger').first().json;
const currentHour = parseInt(scheduleData['Hour']);
const currentMinute = parseInt(scheduleData['Minute']);

// ✅ Crée "now" en heure locale depuis le Schedule Trigger
const now = new Date();
const nowLocal = new Date(now.getTime() + 60 * 60 * 1000); // UTC+1

function shouldRun(s) {
  if (!s.frequency) return false;

  if (s.date_end && new Date(s.date_end + 'T23:59:59') < nowLocal) return false;
  if (s.date_start && new Date(s.date_start + 'T00:00:00') > nowLocal) return false;

  if (s.time) {
    const parts = s.time.split(':');
    const configH = parseInt(parts[0]);
    if (!isNaN(configH) && currentHour !== configH) return false;
  }

  const lastRun = s.last_run ? new Date(s.last_run) : new Date(0);
  const diffHours = (nowLocal - lastRun) / (1000 * 60 * 60);

  if (s.frequency === 'daily') return diffHours >= 20;
  if (s.frequency === 'weekly') return diffHours >= 144;
  if (s.frequency === 'custom') {
    const interval = s.interval || 1;
    if (s.unit === 'hours') return diffHours >= interval * 0.9;
    if (s.unit === 'days') return diffHours >= interval * 24 * 0.9;
    if (s.unit === 'weeks') return diffHours >= interval * 24 * 7 * 0.9;
    if (s.unit === 'months') return diffHours >= interval * 24 * 30 * 0.9;
  }
  return false;
}

const sources = $input.first().json.sources || [];
const toRun = sources.filter(shouldRun);

if (toRun.length === 0) {
  return [{ json: { 
    message: "Aucune veille à lancer", 
    skip: true, 
    checked_at: nowLocal.toISOString(),
    currentHour: currentHour
  }}];
}

return toRun.map(s => ({ json: s }));

// Récupérer le static data global
const workflowData = $getWorkflowStaticData('global');
const processedIds = workflowData.processedIds || [];

// Récupérer les records
const records = $input.first().json.records;

// Filtrer les records déjà traités
const newRecords = records.filter(record => !processedIds.includes(record.fields.idweb));

// Mettre à jour processedIds
workflowData.processedIds = [...processedIds, ...newRecords.map(r => r.fields.idweb)];

// Mapper les records pour le workflow
return newRecords.map(record => ({
  json: {
    idweb: record.fields.idweb,
    objet: record.fields.objet,
    acheteur: record.fields.nomacheteur,
    dateparution: record.fields.dateparution,
    datelimitereponse: record.fields.datelimitereponse || "",
    departement: record.fields.code_departement,
    url_avis: record.fields.url_avis,
    pdf_url: `https://www.boamp.fr/telechargements/FILES/PDF/${record.fields.dateparution.substring(0,4)}/${record.fields.dateparution.substring(5,7)}/${record.fields.idweb}.pdf`
  }
}));

const items = $input.all();
const offers = await Promise.all(items.map(async item => {
  const raw = item.json.text;
  const data = typeof raw === "string" ? JSON.parse(raw) : raw;

  let expectedRevenue = Number(data.expected_revenue);
  if (!expectedRevenue || expectedRevenue <= 0) expectedRevenue = 1000;

  let buId = Number(data.business_unit_id);
  if (!buId || ![2,3,4,5].includes(buId)) buId = 3;

  // ✅ URL offre BOAMP construite depuis idweb
  const idweb = $('extraction les info').first().json.idweb;
  const urlOffre = `https://www.boamp.fr/pages/avis/?q=idweb:"${idweb}"`;

  // ✅ Télécharge le PDF et convertit en base64
  let pdfBase64 = null;
  try {
    const pdfUrl = $('extraction les info').first().json.pdf_url;
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: pdfUrl,
      encoding: 'arraybuffer',
      returnFullResponse: true,
    });
    pdfBase64 = Buffer.from(response.body).toString('base64');
  } catch(e) {
    console.log('Erreur PDF:', e.message);
    pdfBase64 = null;
  }

  return {
    name: data.name || "",
    contact_name: data.contact_name || "",
    email_from: data.email_from || "",
    email_cc: data.email_cc || "",
    phone: data.phone || "",
    function: data.function || "",
    street: data.street || "",
    city: data.city || "",
    zip: data.zip || "",
    company_name: data.company_name || "",
    website: urlOffre,  // ✅ URL BOAMP directe, pas celle du LLM
    date_deadline: data.date_deadline || "",
    expected_revenue: expectedRevenue,
    country_id: 75,
    source_id: 11,
    user_id: 2,
    team_id: 1,
    partner_id: 1,
    business_unit_id: data.business_unit_id, 
    probability: 50,
    Mode_de_livraison: "01 Forfait",
    piste_source_id: (() => {
  try { return $('Webhook').first().json.body.id; } catch(e) {}
  try { return $('shouldRun').first().json.id; } catch(e) {}
  return null;
})(),
    pdf_base64: pdfBase64,
    pdf_filename: `BOAMP_${idweb}.pdf`,
  };
}));


return [{ json: { offers: offers } }];

const llmResponse = $input.first().json.text || "";
const [status, reason] = llmResponse.split('|');
const isValid = status.trim().toUpperCase() === 'VALIDE';

return [{
  json: {
    ...$input.first().json,
    isValid: isValid,
    filterReason: reason ? reason.trim() : 'Pas de raison fournie'
  }
}];
